import{_ as d,o as e,c as r,a2 as o}from"./chunks/framework.DZrHScmQ.js";const u=JSON.parse('{"title":"ARTI Source of Truth","description":"","frontmatter":{},"headers":[],"relativePath":"projects/arti/source-of-truth.md","filePath":"projects/arti/source-of-truth.md"}'),a={name:"projects/arti/source-of-truth.md"};function c(i,t,l,n,s,h){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="arti-source-of-truth" tabindex="-1">ARTI Source of Truth <a class="header-anchor" href="#arti-source-of-truth" aria-label="Permalink to &quot;ARTI Source of Truth&quot;">​</a></h1><p><strong>状态：Current</strong></p><p><strong>核对日期：2026-06-15</strong></p><p>本文件定义项目级所有权。它不取代代码仓库中的可执行真源。</p><h2 id="所有权矩阵" tabindex="-1">所有权矩阵 <a class="header-anchor" href="#所有权矩阵" aria-label="Permalink to &quot;所有权矩阵&quot;">​</a></h2><table tabindex="0"><thead><tr><th>主题</th><th>项目级 Owner</th><th>可执行真源</th><th>主要消费者</th></tr></thead><tbody><tr><td>主站路由与体验</td><td><code>arti</code></td><td><code>src/</code>, <code>vercel.json</code></td><td>Web 用户</td></tr><tr><td>原生预测市场 UI</td><td><code>arti</code></td><td><code>src/predict/</code></td><td>Web 用户</td></tr><tr><td>Prediction Gateway</td><td><code>ARTi-poly</code></td><td><code>api/</code>, gateway 配置</td><td><code>arti/src/predict</code></td></tr><tr><td>重型报告运行时</td><td><code>ARTI_backend</code></td><td><code>modules/reporting/</code>, <code>worker/</code></td><td><code>arti</code>, CLI</td></tr><tr><td>报告结果 DTO</td><td><code>ARTI_backend</code></td><td>assembler、types、result contract</td><td><code>arti</code>, scripts</td></tr><tr><td><code>report_tasks</code> schema</td><td><code>arti</code></td><td><code>supabase/migrations/</code></td><td>Backend、主站</td></tr><tr><td>通知 schema 与 <code>notify_user</code></td><td><code>arti</code></td><td>migrations + notification registry</td><td>Backend、Poly、主站</td></tr><tr><td>Credits 消费与价格</td><td><code>arti</code></td><td>migrations + <code>credit_pricing</code></td><td>Backend、Poly、主站</td></tr><tr><td>预测市场 API 行为</td><td><code>ARTi-poly</code></td><td>serverless handlers</td><td>主站预测 UI</td></tr><tr><td>CLI 命令与 MCP 工具</td><td><code>ARTI-CLI</code></td><td><code>src/</code></td><td>CLI/MCP 用户</td></tr><tr><td>Railway Prompt</td><td><code>ARTI_backend</code></td><td><code>shared/arti_shared/prompts/</code></td><td>Worker/API</td></tr><tr><td>Web <code>AnswerKind</code></td><td><code>arti</code></td><td><code>src/lib/answer-kind.ts</code></td><td>DB 写入、前端展示</td></tr><tr><td>通知类型注册表</td><td><code>arti</code></td><td><code>src/lib/notification-kind.ts</code></td><td>主站通知 UI</td></tr><tr><td>股票代码规范化</td><td>分布式</td><td>Backend resolver + Web normalizer</td><td>全项目</td></tr></tbody></table><h2 id="项目级契约与实现真源" tabindex="-1">项目级契约与实现真源 <a class="header-anchor" href="#项目级契约与实现真源" aria-label="Permalink to &quot;项目级契约与实现真源&quot;">​</a></h2><p>本目录的 <code>contracts/</code> 记录：</p><ul><li>谁拥有契约</li><li>哪些消费者依赖它</li><li>不允许破坏的不变量</li><li>修改时需要联动哪些仓库</li></ul><p>字段、枚举和运行行为仍以 Owner 仓库的代码与 migration 为准。</p><h2 id="共享数据库规则" tabindex="-1">共享数据库规则 <a class="header-anchor" href="#共享数据库规则" aria-label="Permalink to &quot;共享数据库规则&quot;">​</a></h2><ol><li>每个共享表、RPC 和 trigger 只有一个 migration Owner。</li><li>其他仓库可以调用，但不得复制旧 DDL 后整体覆盖。</li><li>已 merge 或已应用的 migration 只追加，不回改。</li><li>修改 <code>CREATE OR REPLACE FUNCTION</code> 前必须核对生产当前定义和其他仓库的新版本。</li><li>文档中的 SQL 示例不能被当作可直接上线的 migration。</li></ol><h2 id="当前未完全收口的真源" tabindex="-1">当前未完全收口的真源 <a class="header-anchor" href="#当前未完全收口的真源" aria-label="Permalink to &quot;当前未完全收口的真源&quot;">​</a></h2><h3 id="prompt-与-agent-registry" tabindex="-1">Prompt 与 Agent Registry <a class="header-anchor" href="#prompt-与-agent-registry" aria-label="Permalink to &quot;Prompt 与 Agent Registry&quot;">​</a></h3><p>Backend 与 CLI 均保存 Prompt，主站保存报告配置。不同运行时确实需要独立加载，但语义一致性尚未自动验证。</p><p>当前规则：</p><ul><li>Railway 报告行为以 Backend 实际加载的 Prompt 为准。</li><li>CLI Prompt 是 CLI 运行时资产。</li><li>跨运行时要求一致时，变更必须显式同步并增加对账验证。</li></ul><h3 id="股票代码规范化" tabindex="-1">股票代码规范化 <a class="header-anchor" href="#股票代码规范化" aria-label="Permalink to &quot;股票代码规范化&quot;">​</a></h3><p>Backend 已有 Python canonical resolver，Web 侧也有 TypeScript 归一逻辑。两者尚未来自同一共享包。</p><p>当前规则：</p><ul><li>存储和跨服务传输使用 canonical symbol。</li><li>港股使用 5 位代码加 <code>.HK</code>。</li><li>A 股使用 6 位代码加 <code>.SS</code> 或 <code>.SZ</code>。</li><li>跨语言实现必须通过共享用例对账。</li></ul>',21)])])}const m=d(a,[["render",c]]);export{u as __pageData,m as default};
